import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

// --- fácilmente AJUSTABLES ---
const USER_ICON_ACTUAL_SIZE = "60px";
const USER_ICON_CONTAINER_PADDING_VALUE = 15;
const TITLE_FONT_SIZE = "32px";
const SMALL_ICON_SVG_SIZE = "22px";
const LABEL_FONT_SIZE = "16px";
const INPUT_FONT_SIZE = "20px";
const BUTTON_FONT_SIZE = "18px";
const MESSAGE_FONT_SIZE = "16px";
// --- FIN DE AJUSTABLES ---

const PALETTE = {
  PRIMARY: "#64B5F6", // Un azul más moderno
  SECONDARY: "#81D4FA", // Un azul más claro como acento
  ACCENT: "#FFAB91", // Un naranja suave para contrastes
  BACKGROUND: "#ECEFF1", // Un gris claro de fondo
  TEXT_PRIMARY: "#263238", // Gris oscuro para el texto principal
  TEXT_SECONDARY: "#78909C", // Gris más claro para detalles
  INPUT_BORDER: "#B0BEC5",
  BUTTON_HOVER: "#42A5F5",
  ERROR: "#E57373",
  SUCCESS: "#81C784",
  WHITE: "#FFFFFF",
  SHADOW_CONTOUR_COLOR: "rgba(0, 0, 0, 0.2)",
};

const UserIcon = ({ color, size = USER_ICON_ACTUAL_SIZE }) => (
  <svg
    viewBox="0 0 24 24"
    style={{ width: size, height: size, fill: color, display: "block" }}
  >
    <path d="M12 12c2.76 0 5-2.24 5-5S14.76 2 12 2 7 4.24 7 7s2.24 5 5 5zm0 2c-3.33 0-10 1.67-10 5v3h20v-3c0-3.33-6.67-5-10-5z" />
  </svg>
);

const EyeIconShow = ({ color, size = SMALL_ICON_SVG_SIZE }) => (
  <svg
    viewBox="0 0 24 24"
    style={{ width: size, height: size, fill: color, display: "block" }}
  >
    <path d="M12 4.5C7 4.5 2.73 7.61 1 12c1.73 4.39 6 7.5 11 7.5s9.27-3.11 11-7.5c-1.73-4.39-6-7.5-11-7.5zM12 17c-2.76 0-5-2.24-5-5s2.24-5 5-5 5 2.24 5 5-2.24 5-5 5zm0-8c-1.66 0-3 1.34-3 3s1.34 3 3 3 3-1.34 3-3-1.34-3-3-3z" />
  </svg>
);

const EyeIconHide = ({ color, size = SMALL_ICON_SVG_SIZE }) => (
  <svg
    viewBox="0 0 24 24"
    style={{ width: size, height: size, fill: color, display: "block" }}
  >
    <path d="M12 7c2.76 0 5 2.24 5 5 0 .65-.13 1.26-.36 1.83l2.92 2.92c1.51-1.26 2.7-2.89 3.44-4.75C21.27 7.61 17 4.5 12 4.5c-1.6 0-3.14.35-4.54.96l1.56 1.56C9.74 7.13 10.85 7 12 7zm-1.07 5.53l2.81 2.81c-.71.15-1.44.26-2.19.26-2.76 0-5-2.24-5-5 0-.75.11-1.48.26-2.19l2.81 2.81c.11.7.42 1.34.81 1.81zM2.71 3.27L1.44 4.54l2.02 2.02C2.03 7.95 1.16 9.77 1 12c1.73 4.39 6 7.5 11 7.5 1.55 0 3.03-.3 4.38-.84l1.53 1.53 1.27-1.27L2.71 3.27z" />
  </svg>
);

const InicioSesion = ({ onLogin, onClose }) => {
  const [usuario, setUsuario] = useState("");
  const [contrasenia, setContrasenia] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [mensaje, setMensaje] = useState(null);
  const [isVisible, setIsVisible] = useState(true);

  const inputVariants = {
    focus: {
      scale: 1.01,
      boxShadow: `0 0 0 1.5px ${PALETTE.ACCENT}`,
      transition: { duration: 0.2 },
    },
  };
  const buttonVariants = {
    hover: { backgroundColor: PALETTE.BUTTON_HOVER, scale: 1.02, transition: { duration: 0.15 } },
  };

  const backdropVariants = {
    hidden: { opacity: 0 },
    visible: { opacity: 1, transition: { duration: 0.2 } },
    exit: { opacity: 0, transition: { duration: 0.2 } },
  };
  const modalVariants = {
    hidden: { scale: 0.95, opacity: 0 },
    visible: { scale: 1, opacity: 1, transition: { type: "spring", stiffness: 100, damping: 15 } },
    exit: { scale: 0.95, opacity: 0, transition: { duration: 0.2 } },
  };
  const iconVariants = {
    hidden: { y: -20, opacity: 0 },
    visible: { y: 0, opacity: 1, transition: { delay: 0.2, type: "spring", stiffness: 120 } },
    exit: { y: -20, opacity: 0, transition: { duration: 0.1 } },
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMensaje(null);

    if (!usuario || !contrasenia) {
      setMensaje("Por favor, rellena todos los campos");
      return;
    }

    setLoading(true);
    try {
      const res = await fetch("http://localhost:3000/usuarios/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ usuario, contrasenia }),
      });
      const data = await res.json();

      if (res.ok && data.encontrado === 1) {
        setMensaje("¡Sesión iniciada!");
        onLogin(data.usuario);
        setTimeout(() => {
          setIsVisible(false);
        }, 1500);
      } else {
        setMensaje(data.mensaje || "Credenciales incorrectas");
      }
    } catch {
      setMensaje("Error de conexión con el servidor");
    } finally {
      setLoading(false);
    }
  };

  const handleClose = () => {
    setIsVisible(false);
  };

  const onExitComplete = () => {
    if (onClose) onClose();
  }

  const labelStyle = {
    fontSize: LABEL_FONT_SIZE,
    color: PALETTE.TEXT_SECONDARY,
    marginBottom: "5px",
    display: "block",
    textAlign: "left",
    fontFamily: "'Montserrat', sans-serif",
  };

  const inputBaseStyle = {
    width: "100%",
    padding: "12px 15px",
    fontSize: INPUT_FONT_SIZE,
    border: `1px solid ${PALETTE.INPUT_BORDER}`,
    borderRadius: "6px",
    backgroundColor: PALETTE.WHITE,
    color: PALETTE.TEXT_PRIMARY,
    fontFamily: "'Caveat', cursive", // Mantener Caveat para el texto dentro del input si es deseado
    boxSizing: "border-box",
    marginBottom: "15px",
  };

  const passwordInputStyle = {
    ...inputBaseStyle,
    paddingRight: "40px",
    marginBottom: "0",
  };

  const iconContainerStyle = {
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    marginBottom: "25px",
  };

  const modalStyle = {
    backgroundColor: PALETTE.BACKGROUND,
    borderRadius: "15px",
    width: "450px", // Slightly larger width
    padding: "30px",
    textAlign: "center",
    fontFamily: "'Montserrat', sans-serif",
    boxShadow: `0 5px 15px ${PALETTE.SHADOW_CONTOUR_COLOR}`,
    position: "relative",
  };

  const mensajeStyle = {
    marginBottom: "20px",
    fontWeight: "bold",
    color: mensaje === "¡Sesión iniciada!" ? PALETTE.SUCCESS : PALETTE.ERROR,
    fontFamily: "'Montserrat', sans-serif",
    fontSize: MESSAGE_FONT_SIZE,
    minHeight: "24px",
  };

  const passwordInputContainerStyle = {
    position: "relative",
    width: "100%",
    marginBottom: "20px",
  };

  const passwordToggleButtonStyle = {
    position: "absolute",
    top: "50%",
    right: "10px",
    transform: "translateY(-50%)",
    background: "none",
    border: "none",
    cursor: "pointer",
    padding: "0",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    color: PALETTE.TEXT_SECONDARY,
    lineHeight: 1,
  };

  const titleStyle = {
    fontSize: TITLE_FONT_SIZE,
    fontWeight: 600,
    color: PALETTE.TEXT_PRIMARY,
    marginBottom: "30px",
    textTransform: "none",
    letterSpacing: "0.5px",
    fontFamily: "'Montserrat', sans-serif",
  };

  const closeButtonStyle = {
    position: "absolute",
    top: "10px",
    right: "15px",
    background: "none",
    border: "none",
    fontSize: "28px",
    cursor: "pointer",
    color: PALETTE.TEXT_SECONDARY,
    lineHeight: 1,
    padding: "5px",
    outline: "none",
  };

  const submitButtonStyle = {
    width: "100%",
    padding: "12px",
    fontSize: BUTTON_FONT_SIZE,
    fontWeight: 500,
    border: "none",
    borderRadius: "6px",
    backgroundColor: PALETTE.PRIMARY,
    color: PALETTE.WHITE,
    cursor: loading ? "not-allowed" : "pointer",
    textTransform: "uppercase",
    opacity: loading ? 0.8 : 1,
    fontFamily: "'Montserrat', sans-serif",
    marginTop: "15px",
  };

  return (
    <AnimatePresence onExitComplete={onExitComplete}>
      {isVisible && (
        <motion.div
          key="backdrop"
          variants={backdropVariants}
          initial="hidden"
          animate="visible"
          exit="exit"
          style={{
            position: "fixed",
            top: 0,
            left: 0,
            width: "100vw",
            height: "100vh",
            backgroundColor: "rgba(0,0,0,0.4)",
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            zIndex: 9999,
          }}
        >
          <motion.div
            key="modal"
            variants={modalVariants}
            initial="hidden"
            animate="visible"
            exit="exit"
            style={modalStyle}
          >
            <button onClick={handleClose} style={closeButtonStyle}>
              &times;
            </button>

            <div style={iconContainerStyle}>
              <motion.div variants={iconVariants} initial="hidden" animate="visible" exit="exit">
                <UserIcon color={PALETTE.PRIMARY} size={USER_ICON_ACTUAL_SIZE} />
              </motion.div>
            </div>

            <h2 style={titleStyle}>Iniciar Sesión</h2>

            {mensaje && <p style={mensajeStyle}>{mensaje}</p>}

            <form onSubmit={handleSubmit} style={{ textAlign: "left" }}>
              <label htmlFor="usuario" style={labelStyle}>
                Usuario
              </label>
              <motion.input
                type="text"
                id="usuario"
                placeholder="Tu nombre de usuario"
                value={usuario}
                onChange={(e) => setUsuario(e.target.value)}
                variants={inputVariants}
                whileFocus="focus"
                style={inputBaseStyle}
              />

              <label htmlFor="contrasenia" style={labelStyle}>
                Contraseña
              </label>
              <div style={passwordInputContainerStyle}>
                <motion.input
                  type={showPassword ? "text" : "password"}
                  id="contrasenia"
                  placeholder="Tu contraseña"
                  value={contrasenia}
                  onChange={(e) => setContrasenia(e.target.value)}
                  variants={inputVariants}
                  whileFocus="focus"
                  style={passwordInputStyle}
                />
                <motion.button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  style={passwordToggleButtonStyle}
                  whileHover={{ opacity: 0.8 }}
                  title={showPassword ? "Ocultar contraseña" : "Mostrar contraseña"}
                >
                  {showPassword ? (
                    <EyeIconHide color={PALETTE.TEXT_SECONDARY} size={SMALL_ICON_SVG_SIZE} />
                  ) : (
                    <EyeIconShow color={PALETTE.TEXT_SECONDARY} size={SMALL_ICON_SVG_SIZE} />
                  )}
                </motion.button>
              </div>

              <motion.button
                type="submit"
                disabled={loading}
                variants={buttonVariants}
                whileHover="hover"
                style={submitButtonStyle}
              >
                {loading ? "Accediendo..." : "Acceder"}
              </motion.button>
            </form>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

export default InicioSesion;
